import{o as s,c as a,D as i}from"./framework.2deede19.js";const d='{"title":"Глава 10","description":"","frontmatter":{"title":"Глава 10","subtitle":"Малини виджайоттара тантра","tags":"malini","date":"2020-09-01T00:00:00.000Z"},"relativePath":"texts/malini-vijayottara/10.md","lastUpdated":1625429874839}',p={},l=i('<div class="stanza"><a href="#s8.1" id="s8.1" class="num">8.1</a><p>Теперь (поведаю) о лакхах (ста тысячах джап), наделяющих успехом в садхане. (Садхака должен обладать) знанием шастр, уравновешенностью, мудростью, неуязвимостью, правдивостью, стойкостью .</p></div><div class="stanza"><a href="#s8.2" id="s8.2" class="num">8.2</a><p>Испытав садхаку (на эти качества) гуру должен укрепить (их). Совершив как подобает почитание Парамешвары как и раньше;</p></div><div class="stanza"><a href="#s8.3" id="s8.3" class="num">8.3</a><p>Вторым (делом он должен установить), как и ранее, сосуд, сделанный из золота и прочего, без повреждений. Во всем (лотосе) в середине лотоса, или в южном лепестке,</p></div><div class="stanza"><a href="#s8.4" id="s8.4" class="num">8.4</a><p>Следует почитать Наяков, с отдельной мантрой цветами и прочим. Выполнив тясячекратную тарпану, следует совершить абхишеку .</p></div><div class="stanza"><a href="#s8.5" id="s8.5" class="num">8.5</a><p>В благоприятной бхадра питхе, у почитаемого дерева шрипарна, поместив (ученика?) лицом на восток или на север, омытого, украшенного цветами и прочим,</p></div><div class="stanza"><a href="#s8.6" id="s8.6" class="num">8.6</a><p>Сотворенное тело мантры, производит благопритные (признаки). Звуки раковины барабана, и прочего, - известны как благоприятные звучащие признаки .</p></div><div class="stanza"><a href="#s8.7" id="s8.7" class="num">8.7</a><p>С всеми царскими упачарами выполнив над ним абхишеку, созерцая его равным Садашиве, следует его украсить .</p></div><div class="stanza"><a href="#s8.8" id="s8.8" class="num">8.8</a><p>Почтив вновь Владыку богов, пусть мудрый даст ему мантру. Пусть поместит (в его тело Ишвару, выполняя абхишеку) водой, цветами, зернами и маслом .</p></div><div class="stanza"><a href="#s8.9" id="s8.9" class="num">8.9</a><p>Все это он должен вылить на голову ученику, приняв (образ) Дакшина мурти. Выполняя абхишеку с астра мантрой он должен явить Рудра Шакти .</p></div><div class="stanza"><a href="#s8.10" id="s8.10" class="num">8.10</a><p>Благодаря им, объединившись с этой (мантрой), следует совершить тарпану тысячу раз. Тогда, настпупит начало, утверждение и объединение с нею .</p></div><div class="stanza"><a href="#s8.11" id="s8.11" class="num">8.11</a><p>Без учителя , абхишеки, (<em>текст поврежден</em>) без правила мантры, как можно (выполнять) адхивасу (<em>текст поврежден</em>) .</p></div><div class="stanza"><a href="#s8.12" id="s8.12" class="num">8.12</a><p>Обретя это труднодостижимое положение не достижимое самостоятельно, садхака, ради (обретения) совершенства в мантре (мантра сиддхи) должен следовать обету мантры .</p></div><div class="stanza"><a href="#s8.13" id="s8.13" class="num">8.13</a><p>Совершив так названную абхишеку, совершив омовение, следует произносить джапу царственной видьи (<em>мантры</em>) сто тысяч раз. Десятую часть от этого (числа) следует совершить тарпану .</p></div><div class="stanza"><a href="#s8.14" id="s8.14" class="num">8.14</a><p>Выполнив, как раньше, абхишеку, следует произносить джапу мантра шираса. Став наполненным обозначенным ею, следует (произносить джапу) два лакха (200 000), несмыкая глаз (без сна) .</p></div><div class="stanza"><a href="#s8.15" id="s8.15" class="num">8.15</a><p>Две лакши (именуются) Рудрани, четыре - Пуруштута, пять лакхов, о Деви (именуются) Пашупата их следует произносить;</p></div><div class="stanza"><a href="#s8.16" id="s8.16" class="num">8.16</a><p>Облачившись в белые, красные, желтые черные и пестрые одежды. Затем садхака защищенный мантрами примет образ (почитаемого божества) .</p></div><div class="stanza"><a href="#s8.17" id="s8.17" class="num">8.17</a><p>Безмолвное произнесение (дает уничтожение) всех грехов усиление силы мантры. Приняв обет ее выпонения, желая практиковать ее;</p></div><div class="stanza"><a href="#s8.18" id="s8.18" class="num">8.18</a><p>Поднеся аргхью, следует благоговейно произносить джапу девять лакхов. После хомы с высшей дравьей (следует выполнить) тарпану десятой частью (от этого числа) .</p></div><div class="stanza"><a href="#s8.19" id="s8.19" class="num">8.19</a><p>(Подносится) мясо, которое именуют Великим владыкой земли, а также другие высшие дравьи, в середине (обряда), выполняя это два раза, три раза и или меньше .</p></div><div class="stanza"><a href="#s8.20" id="s8.20" class="num">8.20</a><p>Масло гунгула (наделяет ) благосклонностью (любовью) женщин, равным ему считается великое мясо (<em>человечина</em>). Молоко, бильва, семена лотоса именуются несравненными на земле .</p></div><div class="stanza"><a href="#s8.21" id="s8.21" class="num">8.21</a><p>Дхатри и дурва равны амрите, им же равным считается масло.</p><p>Следует выполнить затем (обряд) с маслом и прочим, 9, 6, 3 раз по порядку .</p></div><div class="stanza"><a href="#s8.22" id="s8.22" class="num">8.22</a><p>Выполнив это прежде, пусть мудрый ради успеха (сиддхи) поднесет аргхью. Поднеся аргхью, пусть произносит джапу (в зависимости от того,) сколько он желает совершенств (сиддхи) .</p></div><div class="stanza"><a href="#s8.23" id="s8.23" class="num">8.23</a><p>Благодарая одному лакху, Владыка земли приносит силу поддержания. Благодаря двум (лакхам), о Деви (садхака) обретет владычество и привлечение .</p></div><div class="stanza"><a href="#s8.24" id="s8.24" class="num">8.24</a><p>Благодаря трем (лакхам) достигается умиротворение, благодаря четырем - достигается сила. Благодаря пяти -вся мудрость, благодаря шести -сонм гандхарвов .</p></div><div class="stanza"><a href="#s8.25" id="s8.25" class="num">8.25</a><p>Благодаря семи -семь миров, благодаря десяти он станет равен им. Благодаря пятидесяти, он достигнет (состояния) за непроявленным, о Махешвари!</p></div><div class="stanza"><a href="#s8.26" id="s8.26" class="num">8.26</a><p>За Майей, с шестью лакхами, за ишварой с восьмидесятью, благодаря десяти миллионам джап он обретет границу сакалы .</p></div><div class="stanza"><a href="#s8.27" id="s8.27" class="num">8.27</a><p>Затем является сознание Виры, выполнив его. Все (все джапы) как было описано, в темную (половину месяца) днем или ночью, следует выполнять. (Таково) это правило .</p></div><div class="stanza"><a href="#s8.28" id="s8.28" class="num">8.28</a><p>Выполнив описанное выше жертвоприношение, совершив наилучшее возлияние дравьи, пусть произносящий мантру выпрямив туловище, произносит джапу, не пошевелившись, (сидя) лицом на север;</p></div><div class="stanza"><a href="#s8.29" id="s8.29" class="num">8.29</a><p>Выполняя (ее) до тех пор, пока не (проявится) целиком могущество йоги. (Когда он) выполнит (ее), (явится) беспорядочный шум, ужасный и чрезвычайно сильный .</p></div><div class="stanza"><a href="#s8.30" id="s8.30" class="num">8.30</a><p>(Кто) упав на землю сможет подняться и устоять- тот Владыка садхаков. Выполнив для них поклон, отделив левую часть тела .</p></div><div class="stanza"><a href="#s8.31" id="s8.31" class="num">8.31</a><p>И поднявшись к ним, поднеся аргьхю, станет равным им. Даже наставник должен выпоянть (джапу) каждый день сохраняя молчание в течении шести месяцев;</p></div><div class="stanza"><a href="#s8.32" id="s8.32" class="num">8.32</a><p>(Практикуя) десять и пять мантр, которые были раньше названы мной Тебе; связанный предыдущей Ньясой, выполняя трижды (в день)огненный ритуал .</p></div><div class="stanza"><a href="#s8.33" id="s8.33" class="num">8.33</a><p>Следует созерцать описанный выше трезубец, соблюдая брахмачарью, выполнив описанное выше жертвоприношение в окружении трех Шакти .</p></div><div class="stanza"><a href="#s8.34" id="s8.34" class="num">8.34</a><p>Пусть учитель выполнит абхишеку над ним и над собой в начале и в конце. Став принявшим обет, он станет лучшим среди знающих мантру .</p></div><div class="stanza"><a href="#s8.34" id="s8.34" class="num">8.34</a><p>Выполняющий обряды благословения и проклятия, он не может быть уязвим. Для его очищения следует поместить мула мантру, три раза по три .</p></div><div class="stanza"><a href="#s8.36" id="s8.36" class="num">8.36</a><p>В левом большом пальце, ладони, глазах, указательных пальцах, в астре, с мечём А, КША ХРИМ, следует разместить шабдараши (алфавит) .</p></div><div class="stanza"><a href="#s8.37" id="s8.37" class="num">8.37</a><p>(С мантрами) НА, ПХА, ХРИМ (размещаются) старательно образ Шакти. Обратная, махамудра, прайога и мула (мантра);</p><p>В своих местах тела. Это именуется саманья ньясой.</p></div><p>Такова в священной «Малини виджайоттара тантре» десятая глава.</p>',38);p.render=function(i,d,p,n,c,v){return s(),a("div",null,[l])};export default p;export{d as __pageData};
